{
  "terms": [
    {
      "term": "Zs",
      "simpleDefinition": "The total impedance of the entire earth fault loop path, including both internal and external parts.",
      "anchor": "The 'Total' loop resistance that determines if a breaker will trip fast enough.",
      "misconception": "Thinking Zs only measures the earth wire; it actually includes the line conductor and the supplier's equipment too."
    },
    {
      "term": "Ze",
      "simpleDefinition": "The impedance of the external part of the earth fault loop, measured at the start of the installation.",
      "anchor": "The 'External' path provided by the electricity supplier outside the building.",
      "misconception": "Believing Ze includes the resistance of the cables inside the house."
    },
    {
      "term": "R1",
      "simpleDefinition": "The resistance of the line (live) conductor in a circuit.",
      "anchor": "The 'Outward' path that carries current to the point of the fault.",
      "misconception": "Confusing R1 with the neutral conductor; R1 is strictly the line conductor."
    },
    {
      "term": "R2",
      "simpleDefinition": "The resistance of the Circuit Protective Conductor (CPC), commonly known as the earth wire.",
      "anchor": "The 'Internal Return' path that carries fault current from the equipment back to the MET.",
      "misconception": "Thinking R2 is the same as the main earthing conductor; R2 is specific to the individual circuit."
    },
    {
      "term": "MET (Main Earthing Terminal)",
      "simpleDefinition": "The central junction point where all earthing and bonding conductors are connected together.",
      "anchor": "The 'Hub' or meeting point for every earth path in the installation.",
      "misconception": "Thinking the MET is only for bonding pipes; it is a critical link in the fault current's path back to the source."
    },
    {
      "term": "Supplier earth return path",
      "simpleDefinition": "The physical route (such as a cable sheath or dedicated wire) that carries fault current from the MET back to the transformer.",
      "anchor": "The 'Final Leg' of the journey that completes the circuit back to the supply transformer.",
      "misconception": "Believing that fault current simply 'disappears' into the ground rather than returning to the transformer."
    }
  ],
  "anchorPhrases": [
    "Zs = Ze + (R1 + R2)",
    "The complete loop from source to fault and back",
    "Internal path (R1 + R2) vs External path (Ze)",
    "The MET as the central connection point"
  ],
  "misconceptionTargets": [
    "Current does not just go into the ground; it must return to the transformer.",
    "Zs and Ze are not interchangeable; one is the total, the other is just the external part.",
    "R1 and R2 are two different conductors forming the internal part of the loop."
  ]
}

{
  "teachChecks": [
    {
      "title": "The Concept of the Earth Fault Loop",
      "basicQuestions": [
        {
          "questionText": "What is the specific source point that fault current must return to in order to complete the loop?",
          "answerGuidance": [
            "Supply transformer",
            "The transformer",
            "Source transformer"
          ],
          "hint": "It is the equipment owned by the supplier where the electricity originates.",
          "sourceTeachingPointIds": [
            "TP2",
            "TP3"
          ]
        },
        {
          "questionText": "If the impedance of the earth loop is too high, what will happen to the protective device during a fault?",
          "answerGuidance": [
            "It will not trip",
            "It won't trip fast enough",
            "Fail to disconnect"
          ],
          "hint": "Think about whether enough current will flow to trigger the breaker.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        },
        {
          "questionText": "According to the 'loop' concept, where does fault current go after it leaves the metalwork of an appliance?",
          "answerGuidance": [
            "Returns to the source",
            "Returns to the transformer",
            "Back to the supply"
          ],
          "hint": "It does not just disappear into the ground.",
          "sourceTeachingPointIds": [
            "TP5"
          ]
        }
      ],
      "deeperQuestionText": "How does the requirement for a 'complete circle' explain why a circuit breaker fails to operate if the earth path is disconnected?",
